// isPrivateIP checks if an IP address is private or reserved
func isPrivateIP(ipStr string) bool {
	ip := net.ParseIP(ipStr)
	if ip == nil {
		return false
	}

	// Check for IPv4 mapped IPv6 addresses
	if ipv4 := ip.To4(); ipv4 != nil {
		ip = ipv4
	}

	// Private and reserved IP ranges
	privateBlocks := []string{
		"127.0.0.0/8",     // Loopback
		"10.0.0.0/8",      // RFC1918
		"172.16.0.0/12",   // RFC1918
		"192.168.0.0/16",  // RFC1918
		"169.254.0.0/16",  // Link-local
		"::1/128",         // IPv6 loopback
		"fc00::/7",        // IPv6 unique local
		"fe80::/10",       // IPv6 link-local
	}

	for _, block := range privateBlocks {
		_, ipNet, err := net.ParseCIDR(block)
		if err == nil && ipNet.Contains(ip) {
			return true
		}
	}

	// AWS EC2 metadata endpoint
	if ipStr == "169.254.169.254" {
		return true
	}

	return false
}

// safeResolve resolves hostname and validates against private IPs
func safeResolve(hostname string) error {
	// Handle IP addresses directly
	if ip := net.ParseIP(hostname); ip != nil {
		if isPrivateIP(ip.String()) {
			return fmt.Errorf("private IP addresses are not allowed")
		}
		return nil
	}

	// Resolve hostname to IPs
	ips, err := net.LookupIP(hostname)
	if err != nil {
		return err
	}

	// Check all resolved IPs
	for _, ip := range ips {
		if isPrivateIP(ip.String()) {
			return fmt.Errorf("hostname resolves to private IP address")
		}
	}

	return nil
}

