// isPrivateIP checks if the given hostname resolves to a private or reserved IP address
func isPrivateIP(hostname string) bool {
	// If it's already an IP address, check directly
	if ip := netParseIP(hostname); ip != nil {
		return ip.IsPrivate() || ip.IsLoopback() || ip.IsLinkLocalUnicast() || 
			ip.IsLinkLocalMulticast() || ip.IsInterfaceLocalMulticast() ||
			strings.HasPrefix(ip.String(), "192.0.2.") || // TEST-NET-1
			strings.HasPrefix(ip.String(), "198.51.100.") || // TEST-NET-2
			strings.HasPrefix(ip.String(), "203.0.113.") || // TEST-NET-3
			strings.HasPrefix(ip.String(), "255.255.255.255") // Limited broadcast
	}

	// For hostnames, we would normally resolve them, but to prevent DNS-based SSRF
	// and keep this function safe, we'll be conservative and not resolve external names
	// In a production environment, you might want to implement proper DNS resolution
	// with allow/deny lists, but for security, we'll assume any non-IP hostname
	// could potentially resolve to a private IP and block common private patterns

	// Block localhost explicitly
	if hostname == "localhost" || hostname == "LOCALHOST" {
		return true
	}

	// Block common local domains
	localDomains := []string{
		".local",
		".internal",
		".svc",
		".cluster.local",
	}

	for _, domain := range localDomains {
		if strings.HasSuffix(strings.ToLower(hostname), domain) {
			return true
		}
	}

	return false
}

