// isPrivateIP checks if an IP address is in a private or reserved range
func isPrivateIP(ipStr string) bool {
	ip := net.ParseIP(ipStr)
	if ip == nil {
		return false
	}
	if ip.To4() == nil {
		// IPv6
		// Check for IPv4-mapped IPv6 addresses
		if mapped := ip.To4(); mapped != nil {
			ip = mapped
		} else {
			// Check IPv6 private ranges
			privateIPv6Blocks := []string{
				"fc00::/7",  // Unique Local Addresses
				"fe80::/10", // Link-local addresses
				"::1/128",   // Loopback
			}
			for _, block := range privateIPv6Blocks {
				_, ipnet, _ := net.ParseCIDR(block)
				if ipnet.Contains(ip) {
					return true
				}
			}
			return false
		}
	}
	// IPv4
	privateIPBlocks := []string{
		"127.0.0.0/8",    // Loopback
		"10.0.0.0/8",     // Private-use
		"172.16.0.0/12",  // Private-use
		"192.168.0.0/16", // Private-use
		"169.254.0.0/16", // Link-local
		"0.0.0.0/8",      // Current network
		"255.255.255.255/32", // Broadcast
	}
	for _, block := range privateIPBlocks {
		_, ipnet, _ := net.ParseCIDR(block)
		if ipnet.Contains(ip) {
			return true
		}
	}
	return false
}

// safeResolve resolves a hostname and ensures it doesn't resolve to private IPs
func safeResolve(hostname string) (net.IP, error) {
	ips, err := net.LookupIP(hostname)
	if err != nil {
		return nil, err
	}
	for _, ip := range ips {
		if isPrivateIP(ip.String()) {
			return nil, fmt.Errorf("hostname resolves to private IP: %s", ip.String())
		}
	}
	if len(ips) > 0 {
		return ips[0], nil
	}
	return nil, fmt.Errorf("no IPs found for hostname")
}

// safeDialContext creates a dialer that validates IPs before connecting
func safeDialContext(ctx context.Context, network, addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, err
	}

	// Check if host is already an IP
	if ip := net.ParseIP(host); ip != nil {
		if isPrivateIP(host) {
			return nil, fmt.Errorf("connection to private IP blocked: %s", host)
		}
	} else {
		// Host is a domain name - resolve and validate
		ip, err := safeResolve(host)
		if err != nil {
			return nil, err
		}
		host = ip.String()
	}

	// Reconstruct the address with validated IP
	validatedAddr := net.JoinHostPort(host, port)
	dialer := &net.Dialer{}
	return dialer.DialContext(ctx, network, validatedAddr)
}

