// isPrivateIP checks if the given hostname resolves to a private/internal IP address
func isPrivateIP(hostname string) bool {
	// Check for localhost and loopback
	if hostname == "localhost" || hostname == "127.0.0.1" || hostname == "::1" {
		return true
	}

	// Parse as IP directly
	if ip := net.ParseIP(hostname); ip != nil {
		return ip.IsPrivate() || ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast()
	}

	// For domain names, we should resolve them to check if they point to private IPs
	// However, to prevent DNS rebinding attacks and keep it simple, we'll block common private patterns
	// In production, you might want to implement proper DNS resolution with caching and validation

	// Block common internal domain patterns
	internalPatterns := []string{
		".local",
		".internal",
		".corp",
		".lan",
	}

	for _, pattern := range internalPatterns {
		if strings.HasSuffix(strings.ToLower(hostname), pattern) {
			return true
		}
	}

	return false
}

