// WebhookConfig represents the request body for configuring a webhook
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// ConfigureWebhook handles POST requests to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var config WebhookConfig
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Invalid JSON format",
		})
	}

	// Validate that webhook_url is provided
	if config.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "webhook_url is required",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}
	defer client.CloseIdleConnections()

	// Create a new request
	req, err := http.NewRequestWithContext(context.Background(), http.MethodGet, config.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Failed to create request: " + err.Error(),
		})
	}

	// Apply timeout context
	ctxTimeout, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	req = req.WithContext(ctxTimeout)

	// Send test GET request to the webhook URL
	resp, err := client.Do(req)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the response status code indicates success (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error":   "Webhook URL returned non-success status code",
			"status":  resp.StatusCode,
		})
	}

	// TODO: Save the configuration (implementation depends on your storage mechanism)
	// For this example, we'll just simulate saving it successfully

	return ctx.JSON(fiber.Map{
		"message": "Webhook configured successfully",
		"url":     config.WebhookURL,
	})
}

