// isPrivateIP checks if an IP address is private or reserved
func isPrivateIP(ipStr string) bool {
	ip := net.ParseIP(ipStr)
	if ip == nil {
		return false
	}

	// Normalize IPv6-mapped IPv4 addresses
	if ip.To4() != nil {
		ip = ip.To4()
	}

	// Check for private and reserved IP ranges
	privateBlocks := []string{
		"127.0.0.0/8",     // Loopback
		"10.0.0.0/8",      // Private-use
		"172.16.0.0/12",   // Private-use
		"192.168.0.0/16",  // Private-use
		"169.254.0.0/16",  // Link-local
		"::1/128",         // IPv6 loopback
		"fc00::/7",        // IPv6 unique local
		"fe80::/10",       // IPv6 link-local
		"0.0.0.0/8",       // Current network
		"192.0.0.0/24",    // IETF protocol assignments
		"192.0.2.0/24",    // Documentation (TEST-NET-1)
		"198.51.100.0/24", // Documentation (TEST-NET-2)
		"203.0.113.0/24",  // Documentation (TEST-NET-3)
		"224.0.0.0/4",     // Multicast
		"240.0.0.0/4",     // Reserved
	}

	for _, block := range privateBlocks {
		_, ipNet, err := net.ParseCIDR(block)
		if err != nil {
			continue
		}
		if ipNet.Contains(ip) {
			return true
		}
	}
	return false
}

// validateURL checks if the URL is safe to access
func validateURL(u *url.URL) error {
	// Check hostname for localhost
	hostname := strings.ToLower(u.Hostname())
	if hostname == "localhost" || hostname == "127.0.0.1" || hostname == "::1" {
		return fmt.Errorf("access to localhost is not allowed")
	}

	// Check if IP is private/reserved
	if net.ParseIP(hostname) != nil {
		if isPrivateIP(hostname) {
			return fmt.Errorf("access to private IP addresses is not allowed")
		}
	} else {
		// Resolve hostname to check if it resolves to a private IP
		ips, err := net.LookupIP(hostname)
		if err != nil {
			return fmt.Errorf("failed to resolve hostname: %v", err)
		}
		for _, ip := range ips {
			if isPrivateIP(ip.String()) {
				return fmt.Errorf("hostname resolves to a private IP address")
			}
		}
	}

	return nil
}

// ConfigureWebhook handles POST requests to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Validate URL format
	parsedURL, err := url.ParseRequestURI(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format",
		})
	}

	// Ensure the URL has a valid scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must use http or https scheme",
		})
	}

	// Validate URL for SSRF protection
	if err := validateURL(parsedURL); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Invalid webhook URL: %v", err),
		})
	}

	// Create a custom HTTP client with timeout and secure transport
	transport := &http.Transport{
		DialContext: func(ctx context.Context, network, addr string) (net.Conn, error) {
			// Extract host from addr (addr is in form "host:port")
			host, _, err := net.SplitHostPort(addr)
			if err != nil {
				// If SplitHostPort fails, assume addr is just the host
				host = addr
			}

			// Block private IPs at the dial level (DNS rebinding protection)
			if isPrivateIP(host) {
				return nil, fmt.Errorf("connection to private IP blocked")
			}

			dialer := &net.Dialer{
				Timeout:   3 * time.Second,
				KeepAlive: 30 * time.Second,
			}
			return dialer.DialContext(ctx, network, addr)
		},
		TLSHandshakeTimeout:   3 * time.Second,
		ResponseHeaderTimeout: 3 * time.Second,
		ExpectContinueTimeout: 1 * time.Second,
		// Disable redirects
		DisableKeepAlives: true,
	}

	client := &http.Client{
		Transport: transport,
		Timeout:   3 * time.Second,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			// Block all redirects to prevent SSRF via redirects
			return http.ErrUseLastResponse
		},
	}

	// Prepare test payload
	testPayload := webhookTestPayload{
		Message: "Webhook configuration test",
	}
	jsonPayload, err := json.Marshal(testPayload)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to create test payload",
		})
	}

	// Send test request to webhook URL using POST method with the JSON payload
	reqHTTP, err := http.NewRequest("POST", req.WebhookURL, bytes.NewBuffer(jsonPayload))
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Failed to create test request to webhook URL: %v", err),
		})
	}
	reqHTTP.Header.Set("Content-Type", "application/json")

	resp, err := client.Do(reqHTTP)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Failed to send test request to webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check if the webhook responded successfully (2xx status)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook URL returned non-success status: %d", resp.StatusCode),
		})
	}

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

