// isPrivateIP checks if the given hostname resolves to a private or reserved IP address
func isPrivateIP(hostname string) bool {
	// Handle localhost and loopback explicitly
	if hostname == "localhost" || hostname == "127.0.0.1" || hostname == "::1" {
		return true
	}

	// Parse as IP directly
	if ip := net.ParseIP(hostname); ip != nil {
		return ip.IsPrivate() || ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast()
	}

	// For domain names, resolve to IPs and check each
	ips, err := net.LookupIP(hostname)
	if err != nil {
		// If we can't resolve, be safe and assume it might be private
		return true
	}

	for _, ip := range ips {
		if ip.IsPrivate() || ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
			return true
		}
	}
	return false
}

