package main

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"net"
	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/gofiber/fiber/v2"
)

// webhookRequest represents the expected JSON request body
type webhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// webhookTestPayload is the payload sent to test the webhook
type webhookTestPayload struct {
	Message string `json:"message"`
}

// isPrivateIP checks if an IP address is private or reserved
func isPrivateIP(ipStr string) bool {
	ip := net.ParseIP(ipStr)
	if ip == nil {
		return false
	}

	// Check for IPv4 mapped IPv6 addresses
	if ip.To4() != nil {
		ip = ip.To4()
	}

	privateBlocks := []string{
		"127.0.0.0/8",     // Loopback
		"10.0.0.0/8",      // Private-use
		"172.16.0.0/12",   // Private-use
		"192.168.0.0/16",  // Private-use
		"169.254.0.0/16",  // Link-local
		"::1/128",         // IPv6 loopback
		"fc00::/7",        // IPv6 unique local
		"fe80::/10",       // IPv6 link-local
		"ff00::/8",        // IPv6 multicast
	}

	for _, block := range privateBlocks {
		_, ipNet, err := net.ParseCIDR(block)
		if err == nil && ipNet.Contains(ip) {
			return true
		}
	}

	// Check for AWS metadata endpoint (169.254.169.254)
	if ipStr == "169.254.169.254" {
		return true
	}

	return false
}

// safeDialContext creates a dialer that blocks private IPs
func safeDialContext(ctx context.Context, network, addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, fmt.Errorf("invalid address: %v", err)
	}

	// Check if host is already an IP
	if ip := net.ParseIP(host); ip != nil {
		if isPrivateIP(ip.String()) {
			return nil, fmt.Errorf("access to private IP addresses is not allowed")
		}
	} else {
		// Resolve hostname to IPs
		ips, err := net.DefaultResolver.LookupIPAddr(ctx, host)
		if err != nil {
			return nil, fmt.Errorf("failed to resolve hostname: %v", err)
		}

		// Check all resolved IPs
		for _, ipAddr := range ips {
			if isPrivateIP(ipAddr.IP.String()) {
				return nil, fmt.Errorf("access to private IP addresses is not allowed")
			}
		}
	}

	dialer := &net.Dialer{}
	return dialer.DialContext(ctx, network, addr)
}

// ConfigureWebhook handles POST requests to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Validate URL format
	parsedURL, err := url.ParseRequestURI(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format",
		})
	}

	// Ensure the URL has a valid scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must use http or https scheme",
		})
	}

	// Block file and gopher protocols (already handled by scheme check above, but extra safety)
	if strings.HasPrefix(parsedURL.Scheme, "file") || strings.HasPrefix(parsedURL.Scheme, "gopher") {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Unsupported URL scheme",
		})
	}

