func isPrivateIP(ipStr string) bool {
	ip := net.ParseIP(ipStr)
	if ip == nil {
		return false
	}
	if ip.To4() == nil {
		// IPv6
		// Check for IPv4-mapped IPv6 addresses
		if mapped := ip.To4(); mapped != nil {
			ip = mapped
		} else {
			// Check IPv6 private ranges
			privateIPv6Nets := []string{
				"::1/128",         // loopback
				"fc00::/7",        // unique local
				"fe80::/10",       // link-local
				"fec0::/10",       // site-local (deprecated but still reserved)
				"ff00::/8",        // multicast
				"::/128",          // unspecified
				"::ffff:0:0/96",   // IPv4-mapped
