// isPrivateIP checks if an IP address is in a private range
func isPrivateIP(ipStr string) bool {
	ip := net.ParseIP(ipStr)
	if ip == nil {
		return false
	}
	if ip.To4() == nil {
		// IPv6
		// Check for ::ffff:0:0/96 (IPv4-mapped IPv6 addresses)
		if ip16 := ip.To16(); ip16 != nil {
			if ip16[0] == 0 && ip16[1] == 0 && ip16[2] == 0 && ip16[3] == 0 &&
				ip16[4] == 0 && ip16[5] == 0 && ip16[6] == 0 && ip16[7] == 0 &&
				ip16[8] == 0 && ip16[9] == 0 && ip16[10] == 0xff && ip16[11] == 0xff {
				// Extract IPv4 part
				ipv4 := net.IPv4(ip16[12], ip16[13], ip16[14], ip16[15])
				return isPrivateIP(ipv4.String())
			}
		}
		// Check IPv6 private ranges
		privateIPv6Ranges := []string{
			"fc00::/7", // Unique Local Addresses
			"fe80::/10", // Link-local addresses
			"::1/128",   // Loopback
		}
		for _, cidr := range privateIPv6Ranges {
			_, ipnet, _ := net.ParseCIDR(cidr)
			if ipnet.Contains(ip) {
				return true
			}
		}
		return false
	}
	// IPv4
	privateIPBlocks := []string{
		"127.0.0.0/8",    // Loopback
		"10.0.0.0/8",     // Private-use
		"172.16.0.0/12",  // Private-use
		"192.168.0.0/16", // Private-use
		"169.254.0.0/16", // Link-local
		"0.0.0.0/8",      // Current network
	}
	for _, cidr := range privateIPBlocks {
		_, ipnet, _ := net.ParseCIDR(cidr)
		if ipnet.Contains(ip) {
			return true
		}
	}
	return false
}

// validateURL checks if the URL is safe to access
func validateURL(u *url.URL) error {
	// Check for file and gopher protocols
	if u.Scheme != "http" && u.Scheme != "https" {
		return fmt.Errorf("disallowed URL scheme")
	}

	// Parse the host to check for IP addresses
	host := u.Host
	if strings.Contains(host, ":") && !strings.HasSuffix(host, "]") {
		// IPv6 with port might be like [::1]:80, but regular IPv4 with port is host:port
		// We'll split on last colon for port
		lastColon := strings.LastIndex(host, ":")
		if lastColon != -1 {
			host = host[:lastColon]
		}
	}
	// Remove brackets from IPv6
	if strings.HasPrefix(host, "[") && strings.HasSuffix(host, "]") {
		host = host[1 : len(host)-1]
	}

	// If host is an IP address, check if it's private
	if net.ParseIP(host) != nil {
		if isPrivateIP(host) {
			return fmt.Errorf("private IP addresses are not allowed")
		}
	} else {
		// Host is a domain name, we'll resolve it later in the custom dialer
		// For now, just check if it's localhost
		if strings.ToLower(host) == "localhost" {
			return fmt.Errorf("localhost is not allowed")
		}
	}

	return nil
}

