// isPrivateIP checks if the given hostname resolves to a private or reserved IP address
func isPrivateIP(hostname string) bool {
	// Handle IP addresses directly
	if ip := net.ParseIP(hostname); ip != nil {
		return ip.IsPrivate() || ip.IsLoopback() || ip.IsLinkLocalUnicast() || 
			ip.IsLinkLocalMulticast() || ip.IsInterfaceLocalMulticast() ||
			strings.HasPrefix(ip.String(), "0.") || ip.String() == "0.0.0.0"
	}

	// For hostnames, we could resolve them, but to prevent DNS rebinding attacks,
	// it's safer to not resolve arbitrary hostnames in this context.
	// Instead, we'll allow only public hostnames and block anything that might be internal.
	// Common internal patterns:
	internalPatterns := []string{
		"localhost",
		"local",
		"internal",
		"intranet",
		"corp",
		"home",
	}

	hostLower := strings.ToLower(hostname)
	for _, pattern := range internalPatterns {
		if strings.Contains(hostLower, pattern) {
			return true
		}
	}

	// Block obvious private network patterns in hostnames
	privateNetworks := []string{
		"10.",
		"192.168.",
		"172.16.",
		"172.17.",
		"172.18.",
		"172.19.",
		"172.20.",
		"172.21.",
		"172.22.",
		"172.23.",
		"172.24.",
		"172.25.",
		"172.26.",
		"172.27.",
		"172.28.",
		"172.29.",
		"172.30.",
		"172.31.",
	}

	for _, net := range privateNetworks {
		if strings.HasPrefix(hostLower, net) {
			return true
		}
	}

	return false
}

