type webhookConfig struct {
	WebhookURL string `json:"webhook_url" validate:"required"`
}

// global variable to store the webhook configuration (in real applications, use a proper storage)
var currentWebhookURL string

func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON body
	var config webhookConfig
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Invalid JSON format",
		})
	}

	// Validate that webhook_url is not empty
	if config.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "webhook_url is required",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to the webhook URL
	req, err := http.NewRequestWithContext(context.Background(), http.MethodGet, config.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": fmt.Sprintf("Invalid webhook URL: %v", err),
		})
